import { NextResponse } from "next/server";
import { prisma } from "@/lib/prisma";

export async function POST(req: Request) {
    try {
        const { answers } = await req.json();

        // In a real app, we'd get the userId from a session
        // For this prototype, we'll use a placeholder or create a dummy user
        const dummyUser = await prisma.user.upsert({
            where: { email: "student@example.com" },
            update: {},
            create: {
                email: "student@example.com",
                name: "Student One",
                role: "STUDENT",
            },
        });

        const userId = dummyUser.id;

        // Logic to calculate scores by subject (Normally mapping question IDs to subjects)
        // For this mock, we'll assume some scores
        const results = [
            { subject: "Math", score: 75.0 },
            { subject: "Physics", score: 60.0 },
            { subject: "Biology", score: 90.0 },
            { subject: "Chemistry", score: 45.0 },
            { subject: "English", score: 85.0 },
        ];

        // Save Assessment
        await prisma.assessment.create({
            data: {
                userId,
                subject: "Full Diagnostic",
                score: results.reduce((acc, curr) => acc + curr.score, 0) / results.length,
                details: { knowledgeGaps: results.filter(r => r.score < 70) },
            },
        });

        // Update Subject performance
        for (const res of results) {
            await prisma.subject.create({
                data: {
                    userId,
                    name: res.subject,
                    performance: res.score,
                },
            });
        }

        return NextResponse.json({
            success: true,
            message: "Diagnostic results saved successfully.",
            knowledgeGaps: results.filter(r => r.score < 70),
        });
    } catch (error) {
        console.error("API Error:", error);
        return NextResponse.json(
            { success: false, error: "Internal Server Error" },
            { status: 500 }
        );
    }
}
